import qualified Data.Map as Map
import Data.Map (Map)
import Data.Scientific (toRealFloat)
import Data.Aeson (Value(..))

calculateAverageAge :: [Map String Value] -> Double
calculateAverageAge employees =
    let extractAge m = case Map.lookup "age" m of
                          Just (Number n) -> Just (toRealFloat n :: Double)
                          _ -> Nothing
        ages = mapMaybe extractAge employees
    in if null ages then 0.0 else sum ages / fromIntegral (length ages)

