{-# LANGUAGE RecordWildCards #-}
import Data.List (sortBy)
import Data.Ord (comparing)

-- Define the Spot record
data Spot = Spot { name :: String, distance :: Int, photoOpportunities :: Int } deriving (Eq, Show)

organizePhotoTrips :: [Spot] -> [String]
organizePhotoTrips spots = map name sortedSpots
  where
    sortedSpots = sortBy compareSpots spots
    compareSpots s1 s2 = comparing (negate . photoOpportunities) s1 s2 <> comparing distance s1 s2

data Facility = Facility { name :: String, residents :: Int }

calculateTotalResidents :: [Facility] -> Int
calculateTotalResidents facilities = sum (map residents facilities)
